void merge(Node* currHead, Node* head1, Node* head2, bool& isMerged) {
	Node* tail = currHead;
	while (head1 && head2) {
		if (head1->val <= head2->val) {
			tail.next = head1;
			tail.prev = head1.prev;
			head1.prev = tail;
			if (head1.next) head1.next.prev = head1;
			tail = head1;
			}
			else {
				tail.next = head2;
				tail.prev = head2.prev;
			thead2.prev = tail;
			if (head2.next) head2.next.prev = head2;
			tail = head2;
			}
			head1 = head1.next;
			head2 = head2.next;
			}
		if (head1) {
			tail.next = head1;
			tail.prev = head1.prev;
			if (head1.next) head1.next.prev = head1;
			while (head1.next) {
				head1 = head1.next;
			}
			tail = head1;
			}
		else {
			tail.next = head2;
